class XmlNavigator {

    private XmlNavigator() {
    }

    public static Element getChildElement(Element parent, String localName) {
        if (parent == null || localName == null) {
            return null;
        }
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String nodeLocal = element.getLocalName() != null ? element.getLocalName() : element.getNodeName();
                if (localName.equals(nodeLocal)) {
                    return element;
                }
            }
        }
        return null;
    }

    public static String getChildText(Element parent, String namespaceUri, String localName) {
        if (parent == null || localName == null) {
            return null;
        }
        Element child = null;
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String nodeLocal = element.getLocalName() != null ? element.getLocalName() : element.getNodeName();
                String ns = element.getNamespaceURI();
                if (localName.equals(nodeLocal) && (namespaceUri == null || namespaceUri.equals(ns))) {
                    child = element;
                    break;
                }
            }
        }
        return child == null ? null : child.getTextContent();
    }
}

class NSHelper {
    private NSHelper() {
    }

    public static String ns(Element element, String localName) {
        Element child = XmlNavigator.getChildElement(element, localName);
        return child != null ? child.getNamespaceURI() : null;
    }
}

class SoapResponseFactory {

    private SoapResponseFactory() {
    }

    public static SOAPMessage createImportResponse(ImportResult result) throws SOAPException {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage message = factory.createMessage();
        SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
        SOAPBody body = envelope.getBody();

        SOAPElement response = body.addChildElement("ImportDataResponse", "ns1", "http://enterprise.integration.soap/");
        response.addChildElement("BatchId").addTextNode(result.getBatchId());
        response.addChildElement("ReceivedRecords").addTextNode(String.valueOf(result.getReceivedRecords()));
        response.addChildElement("SuccessCount").addTextNode(String.valueOf(result.getSuccessCount()));
        response.addChildElement("FailureCount").addTextNode(String.valueOf(result.getFailureCount()));
        response.addChildElement("ProcessedAt").addTextNode(result.getProcessedAt());

        SOAPElement messages = response.addChildElement("Messages");
        for (String msg : result.getMessages()) {
            messages.addChildElement("Message").addTextNode(msg);
        }

        message.saveChanges();
        return message;
    }

    public static SOAPMessage createHealthResponse(String status, String timestamp) throws SOAPException {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage message = factory.createMessage();
        SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
        SOAPBody body = envelope.getBody();

        SOAPElement response = body.addChildElement("HealthCheckResponse", "ns1", "http://enterprise.integration.soap/");
        response.addChildElement("Status").addTextNode(status);
        response.addChildElement("Timestamp").addTextNode(timestamp);

        message.saveChanges();
        return message;
    }
}

